/*
 * COMP 321 Project 1: Factors
 *
 * This program computes the number of prime factors, and optionally the number
 * of distinct prime factors, for an unsigned integer input.
 * 
 * Student Name, student
 */

#include <assert.h>
#include <math.h>     // Included in case you use the standard math library.
#include <stdbool.h>
#include <stdio.h>
#include <unistd.h>

static unsigned int	count_distinct_factors(unsigned int n);
static unsigned int	count_factors(unsigned int n);
static unsigned int	count_factors_recursive(unsigned int n);
static void		test_factors(void);

// Replace this comment with any global variable declarations.

/* 
 * Requires:
 *   The input "n" must be greater than 1, and "divisor" must be greater than 1.
 *
 * Effects:
 *   Returns the number of prime factors of "n" by recursively testing divisors
 *   starting at "divisor".
 */
static unsigned int	count_factors_recursive_from(unsigned int n,
			    unsigned int divisor);

/* 
 * Requires:
 *   The input "n" must be greater than 1, and "divisor" must be greater than 1.
 *
 * Effects:
 *   Returns the number of prime factors of "n" by recursively testing divisors
 *   starting at "divisor".
 */
static unsigned int
count_factors_recursive_from(unsigned int n, unsigned int divisor)
{

	assert(n > 1);
	assert(divisor > 1);

	if (divisor > n / divisor) {
		return (1);
	}
	if (n % divisor == 0) {
		return (1 + count_factors_recursive_from(n / divisor, divisor));
	}
	return (count_factors_recursive_from(n, divisor + 1));
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors_recursive(unsigned int n)
{
	assert(n > 1);
	return (count_factors_recursive_from(n, 2));
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count;
	unsigned int divisor;

	assert(n > 1);
	count = 0;
	divisor = 2;
	while (divisor <= n / divisor) {
		while (n % divisor == 0) {
			count += 1;
			n /= divisor;
		}
		divisor += 1;
	}
	if (n > 1) {
		count += 1;
	}
	return (count);
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of distinct factors of the input "n".
 */
static unsigned int
count_distinct_factors(unsigned int n)
{
	unsigned int count;
	unsigned int divisor;

	assert(n > 1);
	count = 0;
	divisor = 2;
	while (divisor <= n / divisor) {
		if (n % divisor == 0) {
			count += 1;
			while (n % divisor == 0) {
				n /= divisor;
			}
		}
		divisor += 1;
	}
	if (n > 1) {
		count += 1;
	}
	return (count);
}

/* 
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Runs testing procedures.  Currently only prints a message.
 */
static void
test_factors(void)
{

	assert(count_factors(2) == 1);
	assert(count_factors(12) == 3);
	assert(count_distinct_factors(12) == 2);
	assert(count_factors_recursive(10) == 2);
	printf("Test Factors passed\n");
}

/* 
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   If the "-t" option is specified on the command line, then test code is
 *   executed and the program exits.
 *   
 *   Otherwise, requests a number from standard input.  If the "-r" option is
 *   specified on the command line, then prints the number of prime factors
 *   that the input number has, calculated using a recursive function.
 *   Otherwise, prints the number of prime factors that the input number has
 *   and the number of those factors that are distinct using iterative
 *   functions.
 *
 *   Upon completion, the program always returns 0.
 *
 *   If the number that is input is not between 2 and the largest unsigned
 *   integer, the output of the program is undefined, but it will not crash.
 */
int
main(int argc, char **argv)
{
	unsigned int n;
	int c;
	bool recursive = false;
	bool runtests = false;

	// Parse the command line.
	while ((c = getopt(argc, argv, "rt")) != -1) {
		switch (c) {
		case 'r':             // Use recursive version.
			recursive = true;
			break;
		case 't':             // Run test procedure and exit.
			runtests = true;
			break;
		default:
			break;
		}
	}

	// If "-t" is specified, run test procedure and exit program.
	if (runtests) {
		test_factors();
		return (0);
	}

	// Get input.
	printf("Enter number:\n");
	if (scanf("%u", &n) != 1) {
		fprintf(stderr, "Input error\n");
		return (1);
	}

	// Validate the input.
	if (n < 2) {
		fprintf(stderr, "Invalid input: %u\n", n);
		return (1);
	}

	// Print results.
	if (recursive) {
		// Use recursive version.
		printf("%u has %u prime factors.\n",
		    n, count_factors_recursive(n));
	} else {
		// Use iterative versions.
		printf("%u has %u prime factors, %u of them distinct.\n",
		    n, count_factors(n), count_distinct_factors(n));
	}

	// Report no errors.
	return (0);
}

import sys
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import make_test_result, run_program, compile_c_program


def _run_factors_test(workspace_path: Path, n: int, expected: str, recursive: bool = False):
    executable = workspace_path / "factors"

    if not executable.exists():
        success, error = compile_c_program(workspace_path)
        if not success:
            return make_test_result(False, "compiled", "compilation failed", error)

    args = ["-r"] if recursive else []
    ret_code, stdout, stderr = run_program(executable, args, f"{n}\n", timeout=60)

    if ret_code != 0:
        return make_test_result(False, "exit code 0", f"exit code {ret_code}", stderr)

    if expected in stdout:
        return make_test_result(True, expected, stdout.strip(), None)
    return make_test_result(False, expected, stdout.strip(), None)


def test_factors_power_of_two(workspace):
    return _run_factors_test(
        workspace,
        1024,
        "1024 has 10 prime factors, 1 of them distinct.",
    )


def test_factors_uint_max(workspace):
    return _run_factors_test(
        workspace,
        4294967295,
        "4294967295 has 5 prime factors, 5 of them distinct.",
    )


def test_factors_recursive_prime_power(workspace):
    return _run_factors_test(
        workspace,
        81,
        "81 has 4 prime factors.",
        recursive=True,
    )

